import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch10: CareerQuestion[] = [
  { id: "pta-1601", stem: "A PTA is performing a manual muscle test of the hip extensors in the prone position. Which muscle is the primary hip extensor?", options: ["Rectus femoris", "Gluteus maximus — the primary hip extensor, tested in prone with the knee flexed to isolate it from the hamstrings", "Tensor fasciae latae", "Psoas major"], correctIndex: 1, rationale: "Hip extensor MMT: prone, knee flexed 90° (isolates gluteus maximus from hamstrings). Against gravity. Grade 3+ if the patient can lift the thigh off the table against gravity.", difficulty: 1, category: "Anatomy & Physiology", topic: "hip extensor MMT" },
  { id: "pta-1602", stem: "The peroneal (fibular) nerve wraps around which bony landmark, making it vulnerable to compression?", options: ["Medial malleolus", "Fibular head — compression at this site causes foot drop (inability to dorsiflex the ankle)", "Lateral epicondyle of femur", "Tibial tuberosity"], correctIndex: 1, rationale: "Common peroneal nerve wraps superficially around the fibular head. Compression causes foot drop (ankle dorsiflexion weakness) and numbness on the dorsal foot and lateral leg.", difficulty: 2, category: "Anatomy & Physiology", topic: "peroneal nerve anatomy" },
  { id: "pta-1603", stem: "Normal shoulder flexion ROM is approximately how many degrees?", options: ["90°", "120°", "150°", "180° (0-180° is the normal range)"], correctIndex: 3, rationale: "Normal shoulder flexion: 0-180°. Normal abduction: 0-180°. Normal ER: 0-90°. Normal IR: 0-70-80°. Normal extension: 0-60°.", difficulty: 1, category: "Anatomy & Physiology", topic: "shoulder flexion ROM" },
  { id: "pta-1604", stem: "Which muscle group is responsible for decelerating the leg during terminal swing phase of gait?", options: ["Quadriceps", "Hamstrings — eccentrically control knee extension to prevent hyperextension at terminal swing", "Gastrocnemius", "Hip adductors"], correctIndex: 1, rationale: "Terminal swing: hamstrings eccentrically decelerate the extending knee (preventing hyperextension). Also the tibialis anterior maintains ankle dorsiflexion for heel strike.", difficulty: 2, category: "Anatomy & Physiology", topic: "terminal swing muscles" },
  { id: "pta-1605", stem: "The sacroiliac joint is classified as which type of joint?", options: ["Synovial hinge", "Synovial, diarthrodial joint (irregular/plane type) with limited motion — primarily transmits forces between the spine and lower extremities", "Fibrous syndesmosis", "Cartilaginous symphysis"], correctIndex: 1, rationale: "SI joint: synovial (diarthrodial), plane/irregular type. Very limited motion (2-4° of nutation/counternutation). Primary function: force transmission between spine and pelvis/lower extremities.", difficulty: 2, category: "Anatomy & Physiology", topic: "SI joint classification" },
  { id: "pta-1606", stem: "A patient with shoulder impingement should avoid which movement during exercise?", options: ["Below-shoulder activities", "Overhead reaching in the 'painful arc' (60-120° abduction) and combined shoulder flexion with internal rotation", "Gentle pendulum exercises", "Scapular retraction exercises"], correctIndex: 1, rationale: "Shoulder impingement: avoid the painful arc (60-120° abduction where supraspinatus is compressed), overhead activities, and combined flexion with IR. Focus on scapular stabilization and rotator cuff strengthening.", difficulty: 2, category: "Musculoskeletal", topic: "impingement movement avoidance" },
  { id: "pta-1607", stem: "A patient with chronic Achilles tendinopathy should perform which type of exercise?", options: ["Only rest", "Eccentric heel drops (Alfredson protocol) — slow lowering over the edge of a step, shown to promote tendon remodeling", "Only concentric calf raises", "Maximum jumping exercises"], correctIndex: 1, rationale: "Chronic Achilles tendinopathy: Alfredson eccentric heel drops (3 sets of 15, both straight and bent knee, 2x/day, for 12 weeks). Eccentric loading promotes tendon remodeling and pain reduction.", difficulty: 2, category: "Musculoskeletal", topic: "Achilles tendinopathy eccentric" },
  { id: "pta-1608", stem: "A patient with a posterior cruciate ligament (PCL) injury has which functional limitation?", options: ["Cannot extend the knee", "Difficulty with deceleration, going downstairs, and squatting — the tibia sags posteriorly when the knee is flexed", "Cannot flex the knee", "Only lateral instability"], correctIndex: 1, rationale: "PCL injury: posterior tibial sag, difficulty with deceleration/downstairs/squatting, positive posterior drawer test, and often less functional limitation than ACL tears (quadriceps compensate).", difficulty: 2, category: "Musculoskeletal", topic: "PCL functional limitation" },
  { id: "pta-1609", stem: "A patient has a positive valgus stress test at the knee. What structure is injured?", options: ["ACL", "Medial collateral ligament (MCL) — valgus stress opens the medial joint line", "PCL", "Lateral collateral ligament"], correctIndex: 1, rationale: "Valgus stress test: applies abduction force at the knee with the foot stabilized. Positive (medial opening) = MCL injury. Test at 0° (MCL + posterior capsule) and 30° flexion (isolated MCL).", difficulty: 2, category: "Musculoskeletal", topic: "valgus stress MCL" },
  { id: "pta-1610", stem: "A patient with a calcaneal (Achilles) tendon rupture demonstrates a positive Thompson test. What is the finding?", options: ["Normal calf squeeze response", "Squeezing the calf produces no passive ankle plantarflexion — indicating complete rupture of the Achilles tendon", "Pain with calf squeeze only", "Normal dorsiflexion response"], correctIndex: 1, rationale: "Thompson test: squeeze the calf (posterior). Normal: passive plantarflexion. Positive (abnormal): no plantarflexion = complete Achilles tendon rupture. This is an emergency finding.", difficulty: 2, category: "Musculoskeletal", topic: "Thompson test" },
  { id: "pta-1611", stem: "A patient is performing a stand-to-sit transfer. During the lowering phase, the quadriceps contract:", options: ["Concentrically", "Eccentrically — controlling the rate of knee flexion as the body lowers into the chair", "Isometrically", "Not at all"], correctIndex: 1, rationale: "Stand-to-sit (lowering): quadriceps eccentrically control knee flexion (decelerating the body against gravity). The reverse (sit-to-stand) uses concentric quadriceps contraction.", difficulty: 1, category: "Patient Mobility", topic: "eccentric sit down" },
  { id: "pta-1612", stem: "A patient with a right-side hemiplegia is performing a stand-pivot transfer from the bed to the wheelchair. The wheelchair should be positioned on which side?", options: ["The right (affected) side", "The left (unaffected) side — the patient leads with the stronger leg and pivots toward it", "Either side", "Directly behind the patient"], correctIndex: 1, rationale: "Hemiplegia transfer: wheelchair on the unaffected side. The patient leads with the strong leg, pushes off with the strong arm, and pivots toward the wheelchair. Strong side does the work.", difficulty: 1, category: "Patient Mobility", topic: "hemiplegia transfer direction" },
  { id: "pta-1613", stem: "A patient with a BKA (below-knee amputation) is learning to walk with a prosthesis on uneven terrain. What is the most important skill?", options: ["Walking fast", "Weight acceptance and balance on the prosthetic limb with varying terrain surfaces and inclines", "Ignoring the prosthesis", "Only walking on flat surfaces"], correctIndex: 1, rationale: "Prosthetic uneven terrain: controlled weight acceptance (varied surfaces), ankle strategy simulation, knee control on inclines, visual scanning for hazards, and progressive difficulty.", difficulty: 2, category: "Patient Mobility", topic: "prosthetic uneven terrain" },
  { id: "pta-1614", stem: "A patient using a front-wheeled walker on a ramp should:", options: ["Go as fast as possible", "Lean into the ramp going up, control speed going down, keep body weight over the walker, and use handbrakes if available", "Let go of the walker on ramps", "Turn sideways on ramps"], correctIndex: 1, rationale: "Walker on ramps: lean slightly forward going up, control speed going down (small steps), body weight centered over the walker, and avoid turning on ramps. Use handbrakes (wheeled walkers).", difficulty: 1, category: "Patient Mobility", topic: "walker ramp technique" },
  { id: "pta-1615", stem: "A patient with bilateral lower extremity amputations is learning wheelchair propulsion. What technique helps with uphill surfaces?", options: ["Coast downhill", "Short, powerful strokes with a forward lean, and maintain momentum to avoid rolling backward on the incline", "Normal propulsion", "Ask for a push"], correctIndex: 1, rationale: "Wheelchair uphill: short, frequent, powerful push strokes, forward trunk lean (shifts COM forward), maintain momentum, and use both hands simultaneously with steady cadence.", difficulty: 1, category: "Patient Mobility", topic: "wheelchair uphill technique" },
  { id: "pta-1616", stem: "A PTA is applying moist heat to a patient's lumbar spine. What is the maximum safe application time?", options: ["5 minutes", "20-30 minutes — check the skin at 5 minutes for adverse reactions and maintain a barrier between the hot pack and skin", "60 minutes", "No time limit"], correctIndex: 1, rationale: "Moist heat (hydrocollator pack): 20-30 minutes, 6-8 layers of toweling (barrier), check skin at 5 minutes, remove if excessive redness/pain. Contraindicated over insensate areas.", difficulty: 1, category: "Therapeutic Exercises", topic: "moist heat parameters" },
  { id: "pta-1617", stem: "A patient is performing Russian stimulation for quadriceps strengthening. What frequency is characteristic of Russian stimulation?", options: ["10 Hz", "2500 Hz carrier frequency with a 50 Hz burst rate (beat frequency) for motor-level stimulation", "1 Hz", "100 Hz standard"], correctIndex: 1, rationale: "Russian stimulation: 2500 Hz carrier frequency, burst modulated at 50 Hz. Produces a strong motor contraction. Duty cycle typically 10:50 sec on/off initially. Used for muscle re-education/strengthening.", difficulty: 3, category: "Therapeutic Exercises", topic: "Russian stimulation" },
  { id: "pta-1618", stem: "A PTA is instructing a patient in Williams flexion exercises for lumbar stenosis. Which exercise is included?", options: ["Prone press-ups", "Posterior pelvic tilt, single and double knee-to-chest, and partial sit-ups to open the lumbar intervertebral foramina", "Lumbar extension exercises", "Cervical retraction"], correctIndex: 1, rationale: "Williams flexion exercises: posterior pelvic tilt, knee-to-chest (single/double), partial sit-ups, hamstring stretching, and hip flexor stretching. Open the spinal canal — beneficial for stenosis.", difficulty: 2, category: "Therapeutic Exercises", topic: "Williams flexion exercises" },
  { id: "pta-1619", stem: "When applying interferential current (IFC), four electrodes are placed to create interference. What is the therapeutic benefit?", options: ["Only surface stimulation", "Deeper tissue stimulation with less discomfort — two medium-frequency currents cross in the target tissue creating a low-frequency beat effect", "No therapeutic effect", "Only muscle contraction"], correctIndex: 1, rationale: "IFC: two medium-frequency currents (e.g., 4000 Hz and 4100 Hz) cross to create a 100 Hz beat frequency at the intersection point. Less skin resistance, deeper penetration, and better comfort.", difficulty: 2, category: "Therapeutic Exercises", topic: "IFC mechanism" },
  { id: "pta-1620", stem: "A patient is performing a hip hinge exercise. What is the correct movement pattern?", options: ["Bend at the waist with rounded back", "Maintain neutral spine while flexing at the hips, pushing the hips back and maintaining a slight knee bend — loading the posterior chain", "Stand completely upright", "Bend only at the knees"], correctIndex: 1, rationale: "Hip hinge: maintain neutral spine, flex at the hips (not the lumbar spine), push hips back, slight knee bend. Loads the posterior chain (glutes, hamstrings). Foundation for deadlifts, squats.", difficulty: 1, category: "Therapeutic Exercises", topic: "hip hinge pattern" },
  { id: "pta-1621", stem: "A PTA is using neuromuscular taping (kinesiology tape) for a patient with patellofemoral pain. What is the proposed mechanism?", options: ["Structural support like rigid tape", "Cutaneous sensory input that may alter proprioception, facilitate muscle activation (VMO), and reduce pain through gate control theory", "No therapeutic effect", "Increases muscle strength directly"], correctIndex: 1, rationale: "Kinesiology tape proposed mechanisms: cutaneous sensory input (proprioception), neuromuscular facilitation, pain gate modulation, improved lymphatic/blood flow (skin lifting), and psychological benefit.", difficulty: 2, category: "Therapeutic Exercises", topic: "kinesiology tape mechanism" },
  { id: "pta-1622", stem: "A patient needs an ankle-foot orthosis (AFO) that allows dorsiflexion but blocks plantarflexion. Which type is appropriate?", options: ["Solid AFO", "Hinged AFO with a plantarflexion stop — allows tibial advancement over the foot (dorsiflexion) while preventing foot drop", "Floor reaction AFO", "Posterior leaf spring AFO"], correctIndex: 1, rationale: "Hinged AFO with PF stop: allows DF (tibia advances over foot for stair climbing, sit-to-stand) while blocking PF (prevents foot drop). More functional gait pattern than solid AFO.", difficulty: 2, category: "Assistive Devices", topic: "hinged AFO with PF stop" },
  { id: "pta-1623", stem: "A patient's walker height should be set so that the top of the walker is at the level of:", options: ["The patient's waist", "The patient's greater trochanter or wrist crease when arms hang at the sides — allowing 20-30° elbow flexion during use", "The patient's elbows", "The patient's shoulders"], correctIndex: 1, rationale: "Walker height: top at the greater trochanter or wrist crease level. Allows 20-30° elbow flexion during use. Too high = shoulder shrugging/fatigue. Too low = trunk flexion.", difficulty: 1, category: "Assistive Devices", topic: "walker height" },
  { id: "pta-1624", stem: "A patient with a transfemoral amputation needs to learn hip extension strengthening for proper prosthetic gait. What exercise is MOST important?", options: ["Hip flexion exercises", "Prone hip extension and standing hip extension (gluteus maximus strengthening) for prosthetic stance phase control", "Knee extension exercises", "Only upper body exercises"], correctIndex: 1, rationale: "TF amputation: hip extension (gluteus maximus) is critical for controlling the prosthetic knee during stance phase. Prone hip extension, standing hip extension, and bridging exercises.", difficulty: 2, category: "Assistive Devices", topic: "TF hip extension" },
  { id: "pta-1625", stem: "A patient using a standard wheelchair needs the footrests positioned so that the thighs are:", options: ["Hanging freely", "Parallel to the floor (horizontal) with even weight distribution — footrest hanger length determines this position", "Elevated above the seat", "Pointing downward at a steep angle"], correctIndex: 1, rationale: "Wheelchair footrest height: thighs parallel to the floor, even weight distribution. Too high = increased ischial pressure. Too low = thighs unsupported, pressure on hamstrings.", difficulty: 1, category: "Assistive Devices", topic: "wheelchair footrest height" },
  { id: "pta-1626", stem: "A PTA documents: 'Patient ambulated 150 ft with RW and CGA × 1 on level surfaces.' What does CGA mean?", options: ["Constant guard assist", "Contact guard assist — the therapist maintains hands-on contact with the patient for safety but provides no lifting force", "Close general assist", "Complete guard assist"], correctIndex: 1, rationale: "CGA = Contact Guard Assist: therapist maintains hands-on contact (typically at gait belt) for safety. No lifting or supporting force provided. One step above SBA (standby assist).", difficulty: 1, category: "Documentation", topic: "CGA definition" },
  { id: "pta-1627", stem: "Which section of a SOAP note contains the treatment plan for the next session?", options: ["Subjective", "Plan (P) — includes treatment modifications, frequency, goals updates, and plans for next session", "Objective", "Assessment"], correctIndex: 1, rationale: "Plan section: next session plan, treatment modifications, frequency/duration, updated goals, referrals, equipment needs, and discharge planning. Future-oriented portion of the note.", difficulty: 1, category: "Documentation", topic: "SOAP plan section" },
  { id: "pta-1628", stem: "A PTA needs to document that a patient required help for 50% of a transfer. What assist level is this?", options: ["Minimal assist", "Moderate assist — the patient performs 50-74% of the effort while the therapist provides 26-50%", "Maximum assist", "Total assist"], correctIndex: 1, rationale: "Assist levels: Independent (100%), Modified Independent (device/time), Supervision (standby), Min Assist (75%+ patient effort), Mod Assist (50-74%), Max Assist (25-49%), Total Assist (<25%).", difficulty: 1, category: "Documentation", topic: "moderate assist level" },
  { id: "pta-1629", stem: "What must the PTA do when the patient's status changes significantly (improvement or decline)?", options: ["Nothing — continue treatment", "Notify the supervising PT for re-evaluation and potential treatment plan modification", "Change the treatment plan independently", "Discharge the patient"], correctIndex: 1, rationale: "Significant status change: notify the supervising PT. The PT must re-evaluate and modify the plan of care. The PTA cannot independently change the treatment plan or discharge the patient.", difficulty: 1, category: "Documentation", topic: "status change notification" },
  { id: "pta-1630", stem: "A patient in a burn unit requires PT. What type of room environment is maintained?", options: ["Cold room", "Warm room (85-90°F) to prevent hypothermia — burn patients have impaired thermoregulation due to skin loss", "Normal room temperature", "Very cold for pain relief"], correctIndex: 1, rationale: "Burn unit temperature: 85-90°F (warm). Burn patients lose the ability to thermoregulate through damaged skin. Hypothermia increases metabolic demands and impairs healing.", difficulty: 2, category: "Infection Prevention", topic: "burn unit temperature" },
  { id: "pta-1631", stem: "When performing wound debridement, which technique uses moist gauze to remove non-viable tissue?", options: ["Autolytic debridement", "Wet-to-dry (wet-to-moist) dressing — moist gauze adheres to wound bed, non-selective mechanical debridement when removed", "Sharp debridement", "Enzymatic debridement"], correctIndex: 1, rationale: "Wet-to-dry: moist gauze applied, dries and adheres to wound surface, removes necrotic tissue when removed. Non-selective (also removes healthy tissue). Less commonly used now due to non-selectivity.", difficulty: 2, category: "Infection Prevention", topic: "wet-to-dry debridement" },
  { id: "pta-1632", stem: "A patient's wound shows red, beefy granulation tissue. What stage of healing is this?", options: ["Inflammatory phase", "Proliferative phase — characterized by granulation tissue formation (red, moist, granular appearance) and wound contraction", "Hemostasis", "Maturation/remodeling"], correctIndex: 1, rationale: "Proliferative phase: granulation tissue (red, beefy, granular), wound contraction, angiogenesis, and epithelialization. Duration: approximately days 4-21. Healthy granulation indicates healing.", difficulty: 2, category: "Infection Prevention", topic: "wound healing phase" },
  { id: "pta-1633", stem: "A patient has a pressure injury that extends into the muscle with bone visible. What stage is this?", options: ["Stage 2", "Stage 4 — full thickness tissue loss with exposed bone, tendon, or muscle", "Stage 3", "Unstageable"], correctIndex: 1, rationale: "Stage 4 pressure injury: full thickness tissue loss with exposed bone, tendon, or muscle. Depth varies by anatomical location. May include tunneling and undermining.", difficulty: 2, category: "Infection Prevention", topic: "pressure injury staging" },
  { id: "pta-1634", stem: "A patient receiving PT has a seizure during treatment. After ensuring safety, what should the PTA document?", options: ["Only that a seizure occurred", "Time of onset, duration, type of seizure activity observed, vital signs, patient's post-ictal state, and all actions taken", "Nothing — continue treatment", "Only the time"], correctIndex: 1, rationale: "Seizure documentation: time of onset, duration, observable activity (focal, generalized), loss of consciousness, vital signs, post-ictal state, actions taken, and medical team notification.", difficulty: 1, category: "Patient Safety", topic: "seizure documentation" },
  { id: "pta-1635", stem: "A patient on warfarin (Coumadin) therapy is more susceptible to which exercise-related risk?", options: ["Muscle cramping", "Excessive bleeding from even minor trauma — avoid activities with high risk of falls, contact, or impact", "Dehydration", "Muscle fatigue"], correctIndex: 1, rationale: "Warfarin: increased bleeding risk. Avoid contact activities, high fall risk, and sharp tools. Monitor for bruising, bleeding gums, dark stools, and excessive bleeding from minor injuries.", difficulty: 1, category: "Patient Safety", topic: "warfarin exercise risk" },
  { id: "pta-1636", stem: "A patient's resting blood pressure is 88/56 mmHg. Should the PTA proceed with exercise?", options: ["Yes — low BP is safe", "No — consult with the PT/physician. Hypotension may indicate dehydration, cardiac issues, or medication effects that need evaluation before exercise", "Yes — just monitor closely", "Start with high-intensity exercise"], correctIndex: 1, rationale: "Hypotension (SBP <90): do not exercise until evaluated. May indicate dehydration, cardiac compromise, sepsis, or medication effects. Notify the PT/physician for assessment.", difficulty: 1, category: "Patient Safety", topic: "hypotension exercise" },
  { id: "pta-1637", stem: "A patient demonstrates a positive clonus test at the ankle. What does this indicate?", options: ["Normal finding", "Upper motor neuron lesion — rhythmic involuntary oscillations of the foot in response to sudden dorsiflexion stretch", "Peripheral neuropathy", "Ankle instability"], correctIndex: 1, rationale: "Clonus: sustained rhythmic oscillations (>3 beats is significant) in response to quick stretch. Indicates UMN lesion. Common at the ankle. Seen in stroke, SCI, MS, and cerebral palsy.", difficulty: 2, category: "Neurological Rehabilitation", topic: "clonus" },
  { id: "pta-1638", stem: "A patient post-stroke demonstrates the extension synergy pattern in the lower extremity. Which movements are included?", options: ["Hip flexion, knee flexion", "Hip extension/adduction/IR, knee extension, ankle plantarflexion/inversion — the patient cannot move outside this pattern", "Isolated knee flexion", "Normal voluntary movement"], correctIndex: 1, rationale: "LE extension synergy: hip extension, adduction, IR + knee extension + ankle PF and inversion. Occurs during standing/gait. Limits selective movement needed for normal stepping.", difficulty: 2, category: "Neurological Rehabilitation", topic: "LE extension synergy" },
  { id: "pta-1639", stem: "A patient with Parkinson's disease freezes at a doorway. Which external cue helps overcome freezing?", options: ["Tell the patient to try harder", "Step over an imaginary line (visual cue), march in place (rhythmic cue), or use a metronome/music beat to initiate movement", "Push the patient forward", "Wait indefinitely"], correctIndex: 1, rationale: "PD freezing of gait cues: visual (laser pointer, step over lines/cracks), auditory (metronome, counting, music), attentional (shift weight, rock side-to-side), and march in place to initiate stepping.", difficulty: 2, category: "Neurological Rehabilitation", topic: "PD freezing cues" },
  { id: "pta-1640", stem: "A patient with a complete T12 SCI has which functional mobility expectation?", options: ["Power wheelchair only", "Community ambulation with bilateral KAFOs and forearm crutches may be possible but is energy-intensive; wheelchair is more practical for community distances", "No mobility possible", "Independent walking without aids"], correctIndex: 1, rationale: "T12 SCI: hip flexors partially intact, no LE voluntary control below. Walking with bilateral KAFOs and crutches possible (swing-through pattern) but high energy cost. Wheelchair for community mobility.", difficulty: 2, category: "Neurological Rehabilitation", topic: "T12 SCI mobility" },
  { id: "pta-1641", stem: "A patient with a cerebellar lesion performs the finger-to-nose test and consistently overshoots the target. This is called:", options: ["Intention tremor", "Dysmetria — inability to accurately judge distance and direction of voluntary movements (hypermetria = overshooting)", "Dysdiadochokinesia", "Athetosis"], correctIndex: 1, rationale: "Dysmetria: inaccuracy in movement targeting. Hypermetria = overshoot, Hypometria = undershoot. Cerebellar sign. Often accompanies intention tremor and ataxia.", difficulty: 2, category: "Neurological Rehabilitation", topic: "dysmetria" },
  { id: "pta-1642", stem: "A patient with a complete C4 SCI requires which type of breathing support?", options: ["No breathing support", "Mechanical ventilation or phrenic nerve stimulator — the diaphragm (C3-C5) may be partially or fully denervated", "Only supplemental oxygen", "Pursed-lip breathing training"], correctIndex: 1, rationale: "C4 SCI: diaphragm function may be impaired (C3-C5 innervation). May need mechanical ventilation, phrenic nerve stimulator, or have partial diaphragm function with limited respiratory reserve.", difficulty: 2, category: "Neurological Rehabilitation", topic: "C4 SCI breathing" },
  { id: "pta-1643", stem: "A patient with MS demonstrates the Lhermitte's sign. What does this indicate?", options: ["Hip flexion contracture", "Electric shock-like sensation down the spine and into the limbs with cervical flexion — indicates posterior column demyelination", "Positive straight leg raise", "Ankle clonus"], correctIndex: 1, rationale: "Lhermitte's sign: electric shock sensation radiating down the spine/limbs with cervical flexion. Indicates posterior column (dorsal column) demyelination. Common in MS. Avoid prolonged cervical flexion.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Lhermitte's sign" },
  { id: "pta-1644", stem: "A patient post-ACL reconstruction is at 16 weeks. When can return-to-sport testing typically begin?", options: ["Immediately", "6-9 months post-surgery — must pass functional testing (hop tests, strength >90% of uninvolved, agility tests) before return to full sport", "16 weeks", "2 years"], correctIndex: 1, rationale: "ACL return-to-sport: typically 6-9 months, must pass criteria — quad/hamstring strength >90% of uninvolved, single-leg hop >90%, Y-balance test, agility tests, and surgeon clearance.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "ACL return to sport" },
  { id: "pta-1645", stem: "A patient post-TKR has a continuous passive motion (CPM) machine ordered. What are typical initial settings?", options: ["0-90° immediately", "0-40° initially, increasing 5-10° per day as tolerated to progressively increase knee flexion ROM", "0-130° immediately", "Fixed at 60°"], correctIndex: 1, rationale: "CPM post-TKR: start at 0-40° (or as tolerated), increase 5-10° per day. Speed: 1 revolution per minute. Duration: varies (2-8 hours/day). Goal: minimize adhesion and improve ROM.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "CPM settings" },
  { id: "pta-1646", stem: "A patient with a rotator cuff repair at 4 weeks should limit active ROM to:", options: ["Full ROM", "PROM and AAROM only per surgeon protocol — no active shoulder flexion or abduction to protect the repair from active muscle contraction", "Only isometric exercises", "Full strengthening"], correctIndex: 1, rationale: "Rotator cuff repair at 4 weeks: PROM and AAROM per protocol. No AROM (active muscle contraction stresses the repair). Strengthening typically starts at 8-12 weeks per surgeon guidance.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "rotator cuff repair 4 weeks" },
  { id: "pta-1647", stem: "A patient with lumbar spinal stenosis gets relief with which position?", options: ["Lumbar extension", "Lumbar flexion (sitting, forward bending) — flexion opens the spinal canal and intervertebral foramina, relieving nerve compression", "Standing upright", "Prone lying"], correctIndex: 1, rationale: "Lumbar stenosis: flexion relieves symptoms (opens canal/foramina). Extension worsens (narrows canal). Shopping cart sign (leaning forward). Treatment: flexion exercises, core stabilization.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "stenosis flexion relief" },
  { id: "pta-1648", stem: "A patient with a distal radius fracture (Colles) has been out of the cast for 1 week. What is the treatment focus?", options: ["Maximum resistance", "Gentle AROM (wrist flexion/extension, pronation/supination, finger ROM), edema management, and scar management", "Aggressive PROM", "No treatment for 4 more weeks"], correctIndex: 1, rationale: "Early post-cast Colles: gentle AROM (all wrist/forearm motions), finger mobility, edema control (elevation, compression), scar management (gentle massage), and progressive grip exercises.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "post-cast Colles treatment" },
  { id: "pta-1649", stem: "A patient with a frozen shoulder is in the 'freezing' phase. What characterizes this phase?", options: ["Improving ROM", "Increasing pain and progressive loss of ROM — the capsule is actively inflaming and contracting", "Painless stiffness only", "Full recovery"], correctIndex: 1, rationale: "Freezing phase: progressive pain and ROM loss (weeks to months). Pain often worse at night. Active inflammation of the capsule. Treatment: gentle ROM within tolerance, pain management.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "frozen shoulder freezing phase" },
  { id: "pta-1650", stem: "A patient with a recent hip fracture repaired with ORIF is weight-bearing as tolerated. What gait training is appropriate?", options: ["Running", "Progressive weight-bearing with walker, heel-toe gait pattern, and normalize stride length and speed as pain and strength allow", "Only bed exercises", "Full weight-bearing long walks immediately"], correctIndex: 1, rationale: "Hip fracture ORIF with WBAT: progressive WB with walker (heel-toe pattern), normalize gait, strengthen hip abductors/extensors, and progress assistive device as strength/balance improve.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "hip fracture ORIF gait" },
  { id: "pta-1651", stem: "A PTA is treating a patient in a skilled nursing facility. How often must the PT re-evaluate the patient?", options: ["Never", "At least every 30 days (or as required by state law and facility policy) and whenever there is a significant change in status", "Only at discharge", "Every 6 months"], correctIndex: 1, rationale: "PT re-evaluation: at least every 30 days (many states), with significant status changes, and per facility policy and payer requirements. The PTA can collect data but the PT interprets and modifies the POC.", difficulty: 1, category: "Professional Ethics", topic: "PT re-evaluation frequency" },
  { id: "pta-1652", stem: "Which APTA ethical principle states that PTAs should demonstrate integrity in all professional interactions?", options: ["Autonomy", "Integrity — the obligation to act consistently with professional ethics, maintain honesty, and avoid conflicts of interest", "Beneficence", "Social responsibility"], correctIndex: 1, rationale: "Integrity: act ethically in all interactions, maintain honesty, avoid conflicts of interest, report unethical behavior, and uphold the profession's standards and reputation.", difficulty: 1, category: "Professional Ethics", topic: "integrity principle" },
  { id: "pta-1653", stem: "A PTA is treating a patient and suspects child abuse based on the child's injuries and parental behavior. What is the PTA's legal obligation?", options: ["Discuss with the parent first", "Report suspected abuse to the appropriate state agency (Child Protective Services) — PTAs are mandated reporters", "Wait and observe more", "Only tell the supervising PT"], correctIndex: 1, rationale: "Mandated reporter: report suspected child abuse to Child Protective Services (CPS) or local authorities. Document observations objectively. Do not confront the parent or delay reporting.", difficulty: 1, category: "Professional Ethics", topic: "child abuse reporting" },
  { id: "pta-1654", stem: "When a patient refuses a treatment that has been prescribed, the PTA should:", options: ["Force the treatment", "Respect the patient's right to refuse (autonomy), document the refusal, explain risks of non-treatment, and notify the supervising PT", "Ignore the refusal", "Discharge the patient immediately"], correctIndex: 1, rationale: "Patient refusal: respect autonomy, explain risks of non-treatment (informed decision), document the refusal and education provided, offer alternatives, and notify the supervising PT.", difficulty: 1, category: "Professional Ethics", topic: "treatment refusal" },
  { id: "pta-1655", stem: "A patient with aphasia has difficulty expressing needs during PT. How should the PTA adapt communication?", options: ["Only speak louder", "Use yes/no questions, communication boards, gestures, drawings, and allow extra response time — the patient may understand more than they can express", "Skip communication entirely", "Only written instructions"], correctIndex: 1, rationale: "Aphasia communication: yes/no questions, communication boards, gestures, drawings, demonstration, allow extra time, avoid finishing sentences, and adapt based on aphasia type (expressive vs. receptive).", difficulty: 1, category: "Patient Communication", topic: "aphasia communication" },
  { id: "pta-1656", stem: "A patient from a culture where direct eye contact is considered disrespectful is avoiding eye contact during PT sessions. How should the PTA interpret this?", options: ["The patient is being rude", "Recognize this as a cultural norm — adapt communication style and do not insist on eye contact as a measure of engagement", "The patient is not paying attention", "The patient is hiding something"], correctIndex: 1, rationale: "Cultural competence: eye contact norms vary across cultures. Some cultures consider direct eye contact disrespectful. Adapt communication accordingly and avoid misinterpreting cultural behaviors.", difficulty: 1, category: "Patient Communication", topic: "cultural eye contact" },
  { id: "pta-1657", stem: "A PTA is explaining a home exercise program to a patient with limited health literacy. What approach is MOST effective?", options: ["Give a long written handout", "Use simple language, demonstrate each exercise, have the patient return-demonstrate, use pictures/videos, and limit to 3-5 key exercises", "Use medical terminology", "Only verbal instructions"], correctIndex: 1, rationale: "Limited health literacy: simple language (avoid jargon), demonstrate exercises, return demonstration (teach-back method), visual aids (pictures/video), few exercises (3-5), and written backup.", difficulty: 1, category: "Patient Communication", topic: "health literacy communication" },
  { id: "pta-1658", stem: "When collaborating with the occupational therapist about a patient's upper extremity function, what information should the PTA share?", options: ["Only lower extremity information", "Upper extremity ROM and strength observed during PT activities, functional use of UE during transfers, and any pain or limitations noted", "Nothing — separate disciplines", "Only the patient's pain level"], correctIndex: 1, rationale: "PTA-OT collaboration: share UE observations during PT (strength, ROM, functional use during transfers/mobility), pain, weight-bearing ability, and any changes that affect OT goals.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "PTA-OT collaboration" },
  { id: "pta-1659", stem: "When working with a social worker on a patient's discharge plan, what information does the PTA contribute?", options: ["Only insurance information", "Current mobility status, equipment needs, environmental accessibility requirements, and home safety concerns", "Medical diagnosis only", "Nothing — social work handles discharge"], correctIndex: 1, rationale: "PTA discharge contribution to social work: mobility status, assistive device needs, home accessibility requirements, safety concerns, supervision needs, and transportation considerations.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "PTA social work collaboration" },
  { id: "pta-1660", stem: "A patient post-CABG surgery is in cardiac rehabilitation (Phase II). What exercise intensity is appropriate?", options: ["Maximum intensity", "40-80% of heart rate reserve (Karvonen formula) or RPE 11-14 on the Borg scale, with continuous telemetry monitoring", "No exercise for 3 months", "Only bed exercises"], correctIndex: 1, rationale: "Cardiac rehab Phase II: 40-80% HRR or RPE 11-14, continuous ECG monitoring, 20-40 minutes aerobic, 2-3x/week, and observe sternal precautions. Progress based on symptoms and ECG response.", difficulty: 2, category: "Clinical Case Scenarios", topic: "cardiac rehab Phase II" },
  { id: "pta-1661", stem: "A patient with COPD is performing pulmonary rehabilitation. What is the target exercise intensity?", options: ["Maximum intensity", "60-80% of peak work rate or symptom-limited intensity (Borg dyspnea 3-5/10), with supplemental O2 if prescribed", "Only rest", "10% of maximum capacity"], correctIndex: 1, rationale: "COPD pulmonary rehab: 60-80% peak work rate, Borg dyspnea 3-5/10, supplemental O2 if prescribed, interval training if continuous is not tolerated, and LE + UE exercise.", difficulty: 2, category: "Clinical Case Scenarios", topic: "pulmonary rehab intensity" },
  { id: "pta-1662", stem: "A patient with a femoral neck fracture is 6 weeks post-ORIF. What are the primary PT goals?", options: ["Return to running", "Normalize gait pattern, improve hip abductor/extensor strength, regain full weight-bearing tolerance, and achieve functional independence", "Only stretching", "Only bed mobility"], correctIndex: 1, rationale: "Femoral neck fracture at 6 weeks: normalize gait, strengthen hip abductors/extensors (Trendelenburg prevention), full WB tolerance, functional mobility (stairs, transfers), and fall prevention.", difficulty: 2, category: "Clinical Case Scenarios", topic: "femoral neck fracture goals" },
  { id: "pta-1663", stem: "A patient with diabetes develops a Wagner Grade 2 foot ulcer. What does this classification indicate?", options: ["Superficial wound only", "Deep ulcer penetrating to tendon, bone, or joint — requires aggressive wound management and off-loading", "Gangrene present", "Only skin involvement"], correctIndex: 1, rationale: "Wagner Grade 2: deep ulcer to tendon, bone, or joint capsule (no abscess or osteomyelitis). Requires off-loading (total contact cast, healing shoe), wound care, and monitoring for infection.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Wagner Grade 2" },
  { id: "pta-1664", stem: "A patient with a recent below-knee amputation is 2 weeks post-surgery. What is the primary PT focus?", options: ["Prosthetic gait training", "Residual limb care (wrapping, shaping), general conditioning, transfers, mobility training, and pain management (including phantom pain)", "No PT for 8 weeks", "Only upper body exercise"], correctIndex: 1, rationale: "BKA at 2 weeks: residual limb care (wrapping/shaping), desensitization, LE ROM (prevent contractures), general conditioning, transfers/mobility, phantom pain management, and psychological support.", difficulty: 1, category: "Clinical Case Scenarios", topic: "BKA 2 weeks PT" },
  { id: "pta-1665", stem: "A patient recovering from a hip fracture in a SNF has a Braden Scale score of 14. What does this indicate?", options: ["No risk for pressure injury", "Moderate risk for pressure injury — implement preventive measures including positioning, skin inspection, and nutritional support", "High risk", "Maximum risk"], correctIndex: 1, rationale: "Braden Scale: 15-18 = at risk, 13-14 = moderate risk, 10-12 = high risk, <10 = very high risk. Score of 14: moderate risk. Implement turning schedule, pressure-relieving surfaces, and nutrition support.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Braden Scale" },
  { id: "pta-1666", stem: "A geriatric patient with bilateral knee OA is doing aquatic therapy. What water temperature is recommended?", options: ["Cold water (60°F)", "Warm water (83-90°F / 28-32°C) — promotes muscle relaxation, pain relief, and allows exercise with less joint stress", "Hot water (110°F+)", "Room temperature only"], correctIndex: 1, rationale: "Aquatic therapy for OA: 83-90°F (28-32°C) for therapeutic exercise. Warmer for relaxation (92-96°F). Cooler for vigorous exercise (80-85°F). Warm water reduces pain and spasm.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "aquatic therapy temperature" },
  { id: "pta-1667", stem: "Which screening test evaluates an older adult's fall risk by timing them standing from a chair, walking 10 feet, turning, walking back, and sitting?", options: ["Berg Balance Scale", "Timed Up and Go (TUG) — quick functional mobility screen with established fall risk cutoff scores", "5 Times Sit to Stand", "Dynamic Gait Index"], correctIndex: 1, rationale: "TUG: stand from chair, walk 10 feet (3m), turn, walk back, sit. Normal: <12 seconds. Fall risk: >12-14 seconds. Quick, reliable, and widely used in geriatric screening.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "TUG test" },
  { id: "pta-1668", stem: "A geriatric patient has difficulty getting out of a low chair. What modification helps?", options: ["Only strengthen the quads", "Raise the chair height (firm cushion, leg extenders), use armrests for push-off, and strengthen quadriceps and hip extensors", "Remove all chairs", "Only wheelchair use"], correctIndex: 1, rationale: "Low chair difficulty: raise seat height (add cushion, chair risers), ensure armrests (push-off assistance), strengthen quads/hip extensors, and practice sit-to-stand technique.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "chair height modification" },
  { id: "pta-1669", stem: "At what age does a typically developing child demonstrate independent sitting without support?", options: ["3 months", "6-8 months — the child can sit independently with a protective extension response", "12 months", "18 months"], correctIndex: 1, rationale: "Independent sitting: 6-8 months (initially with hand propping, then ring sitting, then protective reactions). By 8-9 months: sitting with rotation and reaching without falling.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "sitting milestone" },
  { id: "pta-1670", stem: "A child with Down syndrome demonstrates hypotonia. What PT approach is MOST beneficial?", options: ["Avoid all exercise", "Strengthening exercises, balance training, functional activities, and activities that promote proximal stability to support motor development", "Maximum stretching", "Only passive exercises"], correctIndex: 1, rationale: "Down syndrome hypotonia PT: strengthening (especially proximal stability), balance training, functional motor activities, orthotics if needed, and activities promoting developmental milestones.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Down syndrome PT" },
  { id: "pta-1671", stem: "A premature infant is being positioned in the NICU. What position promotes flexion and midline orientation?", options: ["Full extension", "Side-lying with boundaries (swaddling, nesting) that maintain physiological flexion posture and hands near face for self-regulation", "Prone without support", "Supine with limbs extended"], correctIndex: 1, rationale: "NICU positioning: promote physiological flexion, midline orientation, hands near face (self-regulation). Use swaddling, nesting, boundaries. Side-lying facilitates midline hand-to-mouth.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "NICU positioning" },
  { id: "pta-1672", stem: "A child with spina bifida at S1 has which expected functional mobility level?", options: ["Wheelchair dependent", "Community ambulation with AFOs — good prognosis for independent walking with ankle-foot support", "No ambulation possible", "Running and jumping without aids"], correctIndex: 1, rationale: "S1 spina bifida: ankle PF weakness (gastroc/soleus). Community ambulation with AFOs (foot drop control). Good walking prognosis with ankle support and possible mild gait deviations.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "spina bifida S1 mobility" },
  { id: "pta-1673", stem: "A patient recovering from a total ankle replacement is cleared for pool therapy. What aquatic exercise is appropriate?", options: ["Jumping in the pool", "Walking in chest-deep water, ankle ROM exercises with buoyancy assistance, and gentle strengthening with water resistance", "Running on the pool deck", "Deep water diving"], correctIndex: 1, rationale: "Post-ankle replacement aquatic therapy: walking (buoyancy reduces WB), ankle ROM (assisted by buoyancy), gentle strengthening (water resistance), balance activities, and gait normalization.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "ankle replacement aquatics" },
  { id: "pta-1674", stem: "A patient recovering from a tibial shaft fracture with IM nailing is at 10 weeks. What functional activity can begin?", options: ["Return to full sport", "Progressive resistance training, stair climbing, walking program with gradual distance increase, and functional activities of daily living", "Only bed exercises", "Maximum jumping activities"], correctIndex: 1, rationale: "Tibial shaft IM nail at 10 weeks: progressive resistance LE training, stair climbing, walking program (increase distance gradually), functional activities, and monitor for pain/swelling.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "tibial fracture 10 weeks" },
  { id: "pta-1675", stem: "A patient with chronic low back pain has completed an 8-week PT program. What is essential for long-term management?", options: ["Continue PT indefinitely", "Transition to an independent home/gym exercise program with self-management strategies, ergonomic awareness, and periodic follow-up", "Stop all exercise", "Only medication management"], correctIndex: 1, rationale: "Chronic LBP long-term management: independent exercise program, self-management strategies (pacing, ergonomics, flare management), regular physical activity, and periodic PT follow-up as needed.", difficulty: 1, category: "Rehabilitation Planning", topic: "LBP long-term management" },
  { id: "pta-1676", stem: "A patient with an acute exacerbation of COPD is receiving PT in the hospital. What exercise modification is needed?", options: ["Continue at previous intensity", "Reduce exercise intensity significantly, focus on functional mobility and ADLs, monitor SpO2 closely, and use supplemental O2 as prescribed", "Maximum intensity to clear lungs", "No PT during exacerbation"], correctIndex: 1, rationale: "COPD exacerbation: reduce intensity, focus on functional mobility (bed mobility, transfers, ambulation), monitor SpO2 (maintain >88%), use supplemental O2, and progress as symptoms improve.", difficulty: 2, category: "Clinical Case Scenarios", topic: "COPD exacerbation PT" },
  { id: "pta-1677", stem: "A patient is participating in a work hardening program. What distinguishes work hardening from work conditioning?", options: ["They are the same thing", "Work hardening is a multidisciplinary program simulating work tasks in a real/simulated environment; work conditioning is a single-discipline exercise program", "Work conditioning is more intensive", "Work hardening is only stretching"], correctIndex: 1, rationale: "Work hardening: multidisciplinary (PT, OT, psychology, vocational), real/simulated work environment, full day program. Work conditioning: single discipline, exercise-based, focuses on physical capacity.", difficulty: 2, category: "Rehabilitation Planning", topic: "work hardening vs conditioning" },
  { id: "pta-1678", stem: "A patient with a new diagnosis of heart failure is being educated about exercise. What is the MOST important self-monitoring instruction?", options: ["Count calories", "Monitor daily weight (report gain of >2 lbs in 1 day or >5 lbs in 1 week), track symptoms, and report increased dyspnea or edema", "Only track steps", "No self-monitoring needed"], correctIndex: 1, rationale: "Heart failure self-monitoring: daily weight (report >2 lbs/day or >5 lbs/week gain = fluid retention), symptom tracking (dyspnea, edema, fatigue), activity diary, and medication compliance.", difficulty: 2, category: "Patient Education", topic: "heart failure self-monitoring" },
  { id: "pta-1679", stem: "When educating a patient about osteoarthritis self-management, what is the MOST important modifiable risk factor?", options: ["Age", "Body weight — excess weight increases joint load (every 1 lb of body weight = 4 lbs of force at the knee during walking)", "Genetics", "Gender"], correctIndex: 1, rationale: "OA modifiable risk: body weight is the most impactful modifiable factor. Every 1 lb of weight = approximately 4 lbs of knee joint force. Weight loss of even 10% significantly reduces symptoms.", difficulty: 1, category: "Patient Education", topic: "OA weight management" },
  { id: "pta-1680", stem: "A patient asks about the difference between heat and ice for their chronic arthritis. What evidence-based guidance does the PTA provide?", options: ["Never use either", "Heat before exercise (increases tissue extensibility, reduces stiffness) and ice after exercise (reduces post-activity inflammation) — both have analgesic effects", "Only ice for arthritis", "Only heat for arthritis"], correctIndex: 1, rationale: "OA heat vs. ice: heat before exercise (reduces stiffness, increases extensibility), ice after exercise (reduces inflammation). Both provide analgesia. Patient preference also matters.", difficulty: 1, category: "Patient Education", topic: "OA heat ice guidance" },
  { id: "pta-1681", stem: "A PTA is treating a patient with a wound using negative pressure wound therapy (wound VAC). What is the expected outcome?", options: ["Wound drying", "Increased granulation tissue formation, reduced wound size, removal of excess exudate, and promotion of perfusion to the wound bed", "Wound enlargement", "Only pain reduction"], correctIndex: 1, rationale: "Wound VAC outcomes: promotes granulation tissue, reduces wound size, removes excess fluid/exudate, increases local perfusion, reduces bacterial colonization, and provides a moist healing environment.", difficulty: 2, category: "Clinical Case Scenarios", topic: "wound VAC outcomes" },
  { id: "pta-1682", stem: "A patient with a recent L4-L5 spinal fusion is at 6 weeks. What exercise is appropriate?", options: ["Trunk rotation exercises", "Walking program, gentle hip/knee exercises, core isometrics (bracing), and avoid trunk flexion/extension/rotation beyond neutral", "Aggressive trunk flexion", "Running program"], correctIndex: 1, rationale: "L4-L5 fusion at 6 weeks: walking program, gentle LE exercises, isometric core (bracing without movement), avoid trunk flexion/extension/rotation. Brace if prescribed. Follow surgeon protocol.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "spinal fusion 6 weeks" },
  { id: "pta-1683", stem: "A patient with an unstable pelvic fracture is on strict bed rest. What PT intervention is appropriate?", options: ["Ambulation", "Bed mobility with logroll technique, UE exercise, deep breathing/incentive spirometry, ankle pumps for DVT prevention, and gentle isometrics", "Standing exercises", "Maximum LE resistance"], correctIndex: 1, rationale: "Unstable pelvic fracture bed rest: logroll mobility, UE exercises, respiratory exercises, ankle pumps (DVT prevention), gentle isometrics (quads, glutes), and skin care/positioning.", difficulty: 2, category: "Clinical Case Scenarios", topic: "unstable pelvic fracture PT" },
  { id: "pta-1684", stem: "A patient with a wrist fracture is using a TENS unit for pain control. Where should the electrodes be placed?", options: ["Over the fracture site only", "Around (bracketing) the painful area, not directly over the fracture site — two or four electrodes surrounding the pain region", "On the opposite hand", "Only on the shoulder"], correctIndex: 1, rationale: "TENS electrode placement for fracture pain: bracket the painful area (electrodes surrounding but not directly over the fracture site). Avoid placing over open wounds or metal implants.", difficulty: 1, category: "Therapeutic Exercises", topic: "TENS fracture placement" },
  { id: "pta-1685", stem: "A PTA is performing dry needling on a patient with myofascial pain. What is the primary goal?", options: ["Inject medication", "Release myofascial trigger points by inserting a thin needle into the taut band to produce a local twitch response and reduce pain", "Only skin stimulation", "Acupuncture meridians"], correctIndex: 1, rationale: "Dry needling: thin needle inserted into trigger point/taut band. Goal: local twitch response (muscle fiber contraction), pain reduction, improved ROM, and tissue healing. State scope varies.", difficulty: 2, category: "Therapeutic Exercises", topic: "dry needling" },
  { id: "pta-1686", stem: "A patient with lymphedema is performing decongestive exercises. What type of exercise is recommended?", options: ["High-intensity resistance", "Gentle, rhythmic, repetitive movements (pumping exercises) while wearing compression garments to promote lymphatic flow", "Maximum cardio", "No exercise with lymphedema"], correctIndex: 1, rationale: "Lymphedema decongestive exercises: gentle, rhythmic, repetitive (pumping), wear compression during exercise, diaphragmatic breathing, proximal-to-distal progression, and avoid overexertion.", difficulty: 2, category: "Therapeutic Exercises", topic: "lymphedema exercise" },
  { id: "pta-1687", stem: "A patient needs a TLSO (thoracolumbosacral orthosis) after a spinal fracture. What motion does this brace restrict?", options: ["Only rotation", "Flexion, extension, lateral flexion, and rotation of the thoracolumbar spine — provides maximum trunk stabilization", "Only flexion", "No motion restriction"], correctIndex: 1, rationale: "TLSO: restricts all trunk motions (flexion, extension, lateral flexion, rotation). Provides maximum support for thoracolumbar fractures, post-surgical stabilization, and deformity management.", difficulty: 2, category: "Assistive Devices", topic: "TLSO motion restriction" },
  { id: "pta-1688", stem: "A patient using a power wheelchair demonstrates difficulty navigating narrow hallways. What adjustment may help?", options: ["Buy a different wheelchair", "Adjust the joystick sensitivity, practice turning technique, consider a compact power base, and assess environmental modification options", "No adjustments possible", "Only walk in hallways"], correctIndex: 1, rationale: "Power wheelchair narrow spaces: adjust joystick sensitivity (slower speed in tight spaces), practice turning technique, compact base options, and assess environment for widening if possible.", difficulty: 1, category: "Assistive Devices", topic: "power wheelchair navigation" },
  { id: "pta-1689", stem: "A patient with bilateral transtibial amputations needs prosthetic feet. Which foot type provides energy return for an active user?", options: ["SACH foot (solid ankle)", "Dynamic response (energy-storing) carbon fiber foot — stores energy during heel strike and releases it at push-off", "Single-axis foot only", "No foot is appropriate"], correctIndex: 1, rationale: "Dynamic response feet: carbon fiber keel stores energy during loading and releases at push-off. For active ambulators (K3-K4 level). SACH foot for limited ambulators (K1-K2).", difficulty: 2, category: "Assistive Devices", topic: "dynamic response prosthetic foot" },
  { id: "pta-1690", stem: "A patient needs a knee-ankle-foot orthosis (KAFO). What condition typically requires this level of bracing?", options: ["Only ankle weakness", "Quadriceps weakness/paralysis combined with ankle weakness — the KAFO provides knee stability and ankle support for standing and ambulation", "Only knee pain", "Only for children"], correctIndex: 1, rationale: "KAFO indications: quadriceps weakness/paralysis (cannot stabilize the knee) combined with ankle weakness. Provides knee extension stability (locked or unlocked) and ankle control for gait.", difficulty: 2, category: "Assistive Devices", topic: "KAFO indications" },
  { id: "pta-1691", stem: "A patient recovering from a tibial plateau fracture at 12 weeks is progressing well. What outcome measure assesses their functional mobility?", options: ["Only goniometry", "Lower Extremity Functional Scale (LEFS) — a self-report questionnaire assessing difficulty with functional activities on a 0-80 scale", "Only manual muscle testing", "Only pain scale"], correctIndex: 1, rationale: "LEFS: 20-item self-report questionnaire (0-80 scale). Assesses functional difficulty with activities (walking, running, stairs, squatting). MCID = 9 points. Commonly used for LE conditions.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "LEFS" },
  { id: "pta-1692", stem: "A PTA documents: 'Pt amb 250' w/SBQC and Min A x1 on tile, demonstrating improved LE strength and endurance.' Is this adequate documentation?", options: ["Yes — complete and thorough", "Mostly adequate but should also include gait deviations observed, cueing provided, vital signs if applicable, and comparison to prior performance", "Too much detail", "Missing the diagnosis"], correctIndex: 1, rationale: "Good but could improve: add gait quality (deviations), type of cueing, vitals if relevant (cardiac/pulmonary), comparison to previous (progression), and how this relates to goals.", difficulty: 1, category: "Documentation", topic: "documentation completeness" },
  { id: "pta-1693", stem: "A patient with a ventricular assist device (VAD) is participating in PT. What special consideration applies?", options: ["No special considerations", "The patient has no palpable pulse (continuous flow); use RPE for exercise intensity rather than heart rate monitoring", "Maximum intensity exercise", "Only bed rest"], correctIndex: 1, rationale: "VAD considerations: continuous flow = no palpable pulse (use RPE/Borg for intensity), avoid contact near the driveline, battery management, and monitor for signs of device malfunction.", difficulty: 3, category: "Clinical Case Scenarios", topic: "VAD exercise" },
  { id: "pta-1694", stem: "A patient with fibromyalgia reports widespread pain and fatigue. What is the recommended exercise approach?", options: ["Maximum intensity", "Start low, progress slowly: low-intensity aerobic exercise (aquatic, walking), gradual strengthening, and flexibility — exercise should not significantly increase pain", "No exercise", "High-impact training"], correctIndex: 1, rationale: "Fibromyalgia exercise: start low/progress slowly, low-intensity aerobic (aquatic therapy especially effective), gentle strengthening, flexibility, and avoid exercise that significantly increases pain.", difficulty: 1, category: "Clinical Case Scenarios", topic: "fibromyalgia exercise approach" },
  { id: "pta-1695", stem: "When establishing a fall prevention exercise program, which type of exercise has the STRONGEST evidence for reducing falls in older adults?", options: ["Only stretching", "Balance and functional exercises (Tai Chi, Otago Exercise Program) combined with strength training — multicomponent programs", "Only walking", "Only upper body exercise"], correctIndex: 1, rationale: "Strongest fall prevention evidence: balance training (Tai Chi, Otago), strength training (LE), and multicomponent programs. Tai Chi reduces falls by 20-40% in older adults.", difficulty: 2, category: "Rehabilitation Planning", topic: "fall prevention exercise evidence" },
  { id: "pta-1696", stem: "A patient recovering from a hip arthroscopy for labral repair is at 6 weeks. What activity is typically allowed?", options: ["Full squats", "Stationary bike (progressive resistance), aquatic therapy, gentle hip AROM, and progressive weight-bearing per surgeon protocol", "Running and jumping", "No activity for 3 months"], correctIndex: 1, rationale: "Hip arthroscopy labral repair at 6 weeks: stationary bike, pool therapy, gentle AROM, progressive WB, and avoid pivoting/twisting. Strengthening typically progresses at 8-12 weeks.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "hip labral repair 6 weeks" },
  { id: "pta-1697", stem: "A child with a developmental delay is not yet crawling at 12 months. What is the appropriate PT intervention?", options: ["Wait — children develop at their own pace", "Facilitate quadruped positioning, weight-bearing through arms, rocking, and reciprocal movement patterns through play-based activities", "Only standing exercises", "No intervention needed"], correctIndex: 1, rationale: "Crawling delay at 12 months: facilitate quadruped (weight-bearing, rocking), reciprocal movement patterns, tummy time (strengthen extensors), play-based motivation, and parent education.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "crawling delay intervention" },
  { id: "pta-1698", stem: "A patient with a sacral pressure injury (Stage 2) demonstrates a blister with intact serum-filled vesicle. What does Stage 2 indicate?", options: ["Full thickness tissue loss", "Partial thickness skin loss presenting as a shallow open ulcer, abrasion, or intact/ruptured serum-filled blister", "Exposed bone or tendon", "Only redness (non-blanchable)"], correctIndex: 1, rationale: "Stage 2 pressure injury: partial thickness loss of dermis. Shallow open ulcer (red-pink, no slough), intact or ruptured blister (serum-filled). No exposed fat, muscle, or bone.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Stage 2 pressure injury" },
  { id: "pta-1699", stem: "A PTA is treating a patient with peripheral arterial disease (PAD) who develops intermittent claudication during walking. What should the PTA do?", options: ["Stop exercise permanently", "Have the patient rest until the pain subsides (usually 1-3 minutes), then resume walking — this is the expected training response for PAD", "Push through the pain continuously", "Only use upper body exercise"], correctIndex: 1, rationale: "PAD intermittent claudication: walk to moderate claudication pain, rest until subsides (1-3 minutes), resume walking. This interval training approach improves walking distance and peripheral circulation.", difficulty: 2, category: "Clinical Case Scenarios", topic: "PAD claudication exercise" },
  { id: "pta-1700", stem: "A patient is being prepared for discharge from inpatient rehabilitation. What functional outcome must be achieved for safe home discharge?", options: ["Only standing ability", "Safe and independent (or with available caregiver assistance) transfers, functional mobility within the home, and ability to manage basic self-care with whatever equipment is needed", "Perfect balance", "Only upper body strength"], correctIndex: 1, rationale: "Safe discharge criteria: safe transfers (with or without assist), functional home mobility, basic self-care ability, adequate caregiver support if needed, home equipment in place, and emergency plan.", difficulty: 1, category: "Rehabilitation Planning", topic: "discharge criteria" },
];
